#include <bits/stdc++.h>
using namespace std;
struct Node{
    int u,v;
};
int n,k,a[502];
bool check(int x){
    int sum=0,cnt=0;
    for(int i=1;i<=n;i++)
        if(sum+a[i]<=x)
            sum+=a[i];
        else
            sum=a[i],cnt++;
    if(sum)
        cnt++;
    return cnt<=k;
}
void output(int x){
    stack<Node> s;
    int sum=0,last=n;
    for(int i=n;i;i--){
        if(sum+a[i]<=x)
            sum+=a[i];
        else{
            s.push({i+1,last});
            last=i,sum=a[i];
        }
    }
    if(sum)
        s.push({1,last});
    while(s.size()){
        printf("%d %d\n",s.top().u,s.top().v);
        s.pop();
    }
}
int main(){
    int l=0,r=0;
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        r+=a[i];
        l=max(l,a[i]);
    }
    while(l<r){
        int mid=l+r>>1;
        if(check(mid))
            r=mid;
        else
            l=mid+1;
    }
    output(l);
    return 0;
}
